// Detectar si es email o número de pedido
const input = items[0].json.identificador.trim();

let tipo = 'email';
let valor = input;

if (input.includes('@')) {
  // Es un email
  tipo = 'email';
  valor = input;
} else if (input.includes('#') || input.match(/^H?\d+$/i) || input.toUpperCase().startsWith('H')) {
  // Es un número de pedido (H#219901, #219901, H219901, 219901)
  tipo = 'name';
  valor = input;
} else {
  // No reconocido, intentamos como email por defecto
  tipo = 'email';
  valor = input;
}

return [{ json: { tipo, valor } }];

// Obtener el body de la respuesta HTTP
const responseData = items[0].json;

// Verificar si hay pedidos
if (!responseData.orders || responseData.orders.length === 0) {
  return [{
    json: {
      encontrado: false,
      mensaje: "No he encontrado ningún pedido con ese dato. Revisa que esté bien escrito."
    }
  }];
}

// Tomamos el primer pedido encontrado
const order = responseData.orders[0];
const fulfillment = order.fulfillments && order.fulfillments.length > 0 ? order.fulfillments[0] : null;

// Lógica de estados basada en financial_status y fulfillment_status
let estado_texto = "";
let tracking_url = "";
let tracking_number = "";

// Primero verificamos financial_status (tiene prioridad)
if (order.financial_status === 'refunded') {
  estado_texto = "Reembolsado";
} else if (order.financial_status === 'voided') {
  // Voided = pago anulado (ej: contra reembolso no recogido)
  estado_texto = "Cancelado";
} else if (order.cancelled_at) {
  estado_texto = "Cancelado";
} else if (order.fulfillment_status === 'fulfilled' && fulfillment) {
  // Pedido enviado - tiene tracking
  estado_texto = "Enviado";
  tracking_number = fulfillment.tracking_number || "";
  // Construir URL de CTT
  if (tracking_number) {
    tracking_url = `https://www.cttexpress.com/localizador-de-envios/?sc=${tracking_number}`;
  }
} else if (order.fulfillment_status === null) {
  // Pedido no preparado aún
  estado_texto = "En preparación";
} else {
  estado_texto = "En proceso";
}

// Construir mensaje final
let mensaje_final = "";
if (estado_texto === "Enviado" && tracking_url) {
  mensaje_final = `Tu pedido ${order.name} ya ha sido enviado. Puedes hacer seguimiento aquí: ${tracking_url}`;
} else if (estado_texto === "En preparación") {
  mensaje_final = `Tu pedido ${order.name} está en preparación en nuestro almacén. En breve recibirás un email con el número de seguimiento.`;
} else if (estado_texto === "Cancelado") {
  mensaje_final = `Tu pedido ${order.name} ha sido cancelado. Si tienes dudas sobre el motivo, por favor contacta con soporte.`;
} else if (estado_texto === "Reembolsado") {
  mensaje_final = `Tu pedido ${order.name} ha sido reembolsado. El dinero debería aparecer en tu cuenta en unos días.`;
} else {
  mensaje_final = `Tu pedido ${order.name} está actualmente: ${estado_texto}.`;
}

return [{
  json: {
    encontrado: true,
    numero_pedido: order.name,
    email: order.email,
    estado_envio: estado_texto,
    tracking_number: tracking_number,
    tracking_url: tracking_url,
    cliente: order.customer ? order.customer.first_name : "Cliente",
    fecha_pedido: order.created_at.split('T')[0],
    mensaje_final: mensaje_final
  }
}];
